/// 0000-TRANFILE-OPEN
fn p_0000_tranfile_open(state: &mut ProgramState) {
    p_0100_reptfile_open(state);
    p_0200_cardxref_open(state);
    p_0300_trantype_open(state);
    p_0400_trancatg_open(state);
    p_0500_dateparm_open(state);
    p_0550_dateparm_read(state);
    while !(&format!("{}", state.end_of_file) == &"Y".to_string()) {
        // SKIP: unresolved ref
    }
    p_9000_tranfile_close(state);
    p_9100_reptfile_close(state);
    p_9200_cardxref_close(state);
    p_9300_trantype_close(state);
    p_9400_trancatg_close(state);
    p_9500_dateparm_close(state);
    println!("{}", "END OF EXECUTION OF PROGRAM CBTRN03C");
    { let _ = state._fh_transact_file.close();
        let _ = state._fh_xref_file.close();
        let _ = state._fh_trantype_file.close();
        let _ = state._fh_trancatg_file.close();
        let _ = state._fh_report_file.close();
        let _ = state._fh_date_parms_file.close();
        return; }
}

/// 0550-DATEPARM-READ
fn p_0550_dateparm_read(state: &mut ProgramState) {
    date_parms_file_read(state);
    if state.dateparm_status.to_string() == "00" {
        state.appl_result = 0 as i32;
    } else {
        if state.dateparm_status.to_string() == "10" {
            state.appl_result = 16 as i32;
        } else {
            if true {
                state.appl_result = 12 as i32;
            }
        }
    }
    if state.appl_result == 0 {
        println!("{}{}{}{}", "Reporting from ", state.ws_dateparm_record.ws_start_date, " to ", state.ws_dateparm_record.ws_end_date);
    } else {
        if state.appl_result == 0 {
            state.end_of_file = "Y".into();
        } else {
            println!("{}", "ERROR READING DATEPARM FILE");
            {
                let mut _bytes = vec![b' '; 2];
                { let _src = state.dateparm_status.dateparm_stat1.as_bytes(); let _end = (0+1).min(_bytes.len()); let _cl = _src.len().min(_end-0); _bytes[0..0+_cl].copy_from_slice(&_src[.._cl]); }
                { let _src = state.dateparm_status.dateparm_stat2.as_bytes(); let _end = (1+1).min(_bytes.len()); let _cl = _src.len().min(_end-1); _bytes[1..1+_cl].copy_from_slice(&_src[.._cl]); }
                let _len = _bytes.len();
                if _len > 0 { let _end = _len.min(0+1); state.io_status.io_stat1 = FixedString::from(String::from_utf8_lossy(&_bytes[0.._end])); }
                if _len > 1 { let _end = _len.min(1+1); state.io_status.io_stat2 = FixedString::from(String::from_utf8_lossy(&_bytes[1.._end])); }
            }
            p_9910_display_io_status(state);
            p_9999_abend_program(state);
        }
    }
}

