/// 1100-WRITE-TRANSACTION-REPORT
fn p_1100_write_transaction_report(state: &mut ProgramState) {
    if &format!("{}", state.ws_report_vars.ws_first_time) == &"Y".to_string() {
        state.ws_report_vars.ws_first_time = "N".into();
        state.report_name_header.rept_start_date = FixedString::copy_from(&state.ws_dateparm_record.ws_start_date);
        state.report_name_header.rept_end_date = FixedString::copy_from(&state.ws_dateparm_record.ws_end_date);
        p_1120_write_headers(state);
    }
    if state.ws_report_vars.ws_line_counter.value() == 0i64 {
        p_1110_write_page_totals(state);
        p_1120_write_headers(state);
    }
    state.ws_report_vars.ws_page_total += i64::from(state.tran_record.tran_amt);
    p_1120_write_detail(state);
}

/// 1110-WRITE-PAGE-TOTALS
fn p_1110_write_page_totals(state: &mut ProgramState) {
    state.report_page_totals.rept_page_total = cobol_runtime::format_edited(state.ws_report_vars.ws_page_total.value, 2, "+ZZZ,ZZZ,ZZZ").as_str().into();
    state.fd_reptfile_rec = FixedString::copy_from(&state.report_page_totals);
    p_1111_write_report_rec(state);
    state.ws_report_vars.ws_grand_total += i64::from(state.ws_report_vars.ws_page_total);
    state.ws_report_vars.ws_page_total = (0).into();
    state.ws_report_vars.ws_line_counter += PackedDecimal::new(1i64);
    state.fd_reptfile_rec = FixedString::copy_from(&state.transaction_header_2);
    p_1111_write_report_rec(state);
    state.ws_report_vars.ws_line_counter += PackedDecimal::new(1i64);
}

