/// READ TRANSACT-FILE
fn transact_file_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_transact_file.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(350);
            if _len > 0 { let _end = _len.min(0+304); state.fd_trans_data = FixedString::from(String::from_utf8_lossy(&_bytes[0.._end])); }
            if _len > 304 { let _end = _len.min(304+26); state.fd_tran_proc_ts = FixedString::from(String::from_utf8_lossy(&_bytes[304.._end])); }
            if _len > 330 { let _end = _len.min(330+20); state.fd_filler = FixedString::from(String::from_utf8_lossy(&_bytes[330.._end])); }
            state._fs_transact_file = FileStatus::Success;
    { let _s = format!("{}", state._fs_transact_file); let _b = _s.as_bytes(); unsafe { let p = &mut state.tranfile_status as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(FileStatus::AtEnd) => {
            state._fs_transact_file = FileStatus::AtEnd;
    { let _s = format!("{}", state._fs_transact_file); let _b = _s.as_bytes(); unsafe { let p = &mut state.tranfile_status as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(e) => {
            state._fs_transact_file = e.clone();
    { let _s = format!("{}", state._fs_transact_file); let _b = _s.as_bytes(); unsafe { let p = &mut state.tranfile_status as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
    }
    Ok(())
}

/// WRITE to TRANSACT-FILE
fn transact_file_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 350];
    { let _src = state.fd_trans_data.as_bytes(); let _end = (0+304).min(_buf.len()); let _cl = _src.len().min(_end-0); _buf[0..0+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.fd_tran_proc_ts.as_bytes(); let _end = (304+26).min(_buf.len()); let _cl = _src.len().min(_end-304); _buf[304..304+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.fd_filler.as_bytes(); let _end = (330+20).min(_buf.len()); let _cl = _src.len().min(_end-330); _buf[330..330+_cl].copy_from_slice(&_src[.._cl]); }
    match state._fh_transact_file.write_record(&_buf) {
        Ok(()) => state._fs_transact_file = FileStatus::Success,
        Err(e) => state._fs_transact_file = e,
    }
}

